// ============================================
// 헬퍼 함수들 (job_matcher.py와 동일)
// ============================================

function _parseEmploymentTypes(employmentStr) {
  /** 고용형태 문자열 파싱 */
  if (!employmentStr) return [];
  return employmentStr.split(",").map(emp => emp.trim()).filter(emp => emp);
}

function _simpleMatch(jobField, targetJob) {
  /** 단순 문자열 매칭 */
  if (!jobField || !targetJob) return false;
  return targetJob.toLowerCase().replace(/\s/g, "") 
    .includes(jobField.toLowerCase().replace(/\s/g, "")) ||
    jobField.toLowerCase().replace(/\s/g, "")
    .includes(targetJob.toLowerCase().replace(/\s/g, ""));
}

function _isJobMatch(job, targetJobs) {
  /** 직무 매칭 여부 판단 */
  if (!targetJobs || targetJobs.length === 0) return true;

  const processedPosition = job.processed_position_name || "";
  for (const targetJob of targetJobs) {
    if (!targetJob) continue;
    if (processedPosition && processedPosition !== "미분류") {
      if (_simpleMatch(processedPosition, targetJob)) {
        return true;
      }
    }
  }
  return false;
}

function _isEducationMatch(userEduList, jobEducation) {
  for (const userEdu of userEduList) {
    // 양방향 포함 체크
    if (jobEducation.includes(userEdu) || userEdu.includes(jobEducation)) {
      return true;
    }

    // 학사 4년 특수 케이스
    if ((userEdu.includes("학사") && userEdu.includes("4년")) &&
        (jobEducation.includes("대학") && jobEducation.includes("4년"))) {
      return true;
    }
  }
  return false;
}

function isPreferredCompany(targetCompanies, jobCompany) {
  /** 희망기업 여부 확인 */
  if (!targetCompanies || targetCompanies.length === 0 || !jobCompany) {
    return false;
  }

  // 1. 직접 매칭
  if (targetCompanies.includes(jobCompany)) return true;

  // 2. 매핑 테이블을 통한 매칭
  for (const targetCompany of targetCompanies) {
    let mappedNames = companyNameMapping[targetCompany] || [];
    if (typeof mappedNames === "string") mappedNames = [mappedNames];

    for (const mappedName of mappedNames) {
      if (mappedName === jobCompany) return true;
      // 부분 매칭
      if (mappedName.toLowerCase().includes(jobCompany.toLowerCase()) ||
          jobCompany.toLowerCase().includes(mappedName.toLowerCase())) {
        return true;
      }
    }
  }

  // 3. 기본 부분 문자열 매칭
  const jobCompanyClean = jobCompany.toLowerCase().replace(/[\s\/]/g, "");
  for (const targetCompany of targetCompanies) {
    const targetClean = targetCompany.toLowerCase().replace(/[\s\/]/g, "");
    if (targetClean.includes(jobCompanyClean) || jobCompanyClean.includes(targetClean)) {
      return true;
    }

    if (jobCompany.includes("/")) {
      const companyBase = jobCompany.split("/")[0].toLowerCase().replace(/\s/g, "");
      if (targetClean.includes(companyBase) || companyBase.includes(targetClean)) {
        return true;
      }
    }
  }

  return false;
}

function countNulls(jobDict) {
  /** 채용공고의 NULL 개수 계산 */
  const checkFields = ["min_education_level", "min_experience_level", "employment_type"];
  return checkFields.filter(field => 
    !jobDict[field] || jobDict[field] === "확인불가"
  ).length;
}

function getJobRolePriority(targetJobs, job) {
  /** 직무 우선순위 계산 (낮을수록 우선순위 높음) */
  for (let i = 0; i < targetJobs.length; i++) {
    if (targetJobs[i] && _isJobMatch(job, [targetJobs[i]])) {
      return i + 1;
    }
  }
  return 5;
}

function getPriority(userValues, jobValue) {
  /** 공통 우선순위 계산 함수 */
  if (!jobValue || jobValue === "확인불가") return 2;
  if (!userValues || userValues.length === 0) return 3;
  return userValues.includes(jobValue) ? 1 : 3;
}

function _extractTargetCompanies(userData) {
  /** 사용자가 관심있는 회사들 추출 */
  const companies = [];

  for (const [groupName, groupInfo] of Object.entries(companyMappings)) {
    const groupSelection = userData[groupInfo.key] || "";
    if (groupSelection && groupSelection.trim()) {
      if (groupSelection.includes("전체")) {
        companies.push(...groupInfo.companies);
        console.log(`'${groupName} 전체' 선택됨 → ${groupInfo.companies.length}개 회사 추가`);
      } else {
        const selected = groupSelection.split(",").map(c => c.trim()).filter(c => c);
        companies.push(...selected);
        console.log(`'${groupName}' 개별 선택 → ${selected}`);
      }
    }
  }

  return [...new Set(companies)]; // 중복 제거
}

// ============================================
// 필터링 함수들 (job_matcher.py와 동일)
// ============================================

function applyBasicFilters(userData, jobPostings) {
  /** 1단계 필터링: 신입 공고만 추출 */
  const filteredJobs = [];
  const careerPreference = userData["찾고 계신 공고의 경력 조건을 선택해주세요."] || "";

  for (const job of jobPostings) {
    const experienceLevel = job.min_experience_level || "";
    if (careerPreference.includes("신입")) {
      if (["신입", "확인불가", ""].includes(experienceLevel)) {
        filteredJobs.push(job);
      }
    } else {
      filteredJobs.push(job);
    }
  }
  return filteredJobs;
}

function filterByEmploymentType(userData, jobPostings) {
  /** 2단계 필터링: 고용형태 */
  const filteredJobs = [];
  const targetEmploymentTypes = _parseEmploymentTypes(
    userData["희망 고용 형태 (복수선택)"] || ""
  );

  for (const job of jobPostings) {
    const employmentType = job.employment_type || "";
    if (!employmentType ||
        employmentType === "확인불가" ||
        targetEmploymentTypes.length === 0 ||
        targetEmploymentTypes.includes(employmentType)) {
      filteredJobs.push(job);
    }
  }
  return filteredJobs;
}

function filterByJobRole(userData, jobPostings) {
  /** 3단계 필터링: 직무 */
  const filteredJobs = [];
  let targetJobs = [
    userData["희망 직무 1순위 (필수응답)"] || "",
    userData["희망 직무 2순위 "] || "",  // 공백 포함!
    userData["희망 직무 3순위 "] || "",  // 공백 포함!
  ];
  targetJobs = targetJobs.map(job => job.trim()).filter(job => job);

  for (const job of jobPostings) {
    if (targetJobs.length === 0 || _isJobMatch(job, targetJobs)) {
      filteredJobs.push(job);
    }
  }
  return filteredJobs;
}

function filterByEducation(userData, jobPostings) {
  /** 4단계 필터링: 학력 */
  const filteredJobs = [];
  const userEducation = userData["찾고 계신 공고의 학력 조건을 선택해주세요. (졸업예정자도 선택 가능, 복수선택)"] || "";
  const userEduList = userEducation.split(",").map(edu => edu.trim()).filter(edu => edu);

  for (const job of jobPostings) {
    const education = job.min_education_level || "";
    if (!education ||
        education === "학력_확인불가" ||
        userEduList.length === 0 ||
        _isEducationMatch(userEduList, education)) {
      filteredJobs.push(job);
    }
  }
  return filteredJobs;
}

// ============================================
// 메인 매칭 함수 (job_matcher.py의 match_jobs_for_user)
// ============================================

function matchJobsForUser(userData, jobData, topN = 100) {
  /** 사용자에게 맞는 채용공고 매칭 */
  console.log("=== 필터링 시작 ===");

  // 사용자 선호도 추출
  const targetCompanies = _extractTargetCompanies(userData);
  let targetJobs = [
    userData["희망 직무 1순위 (필수응답)"] || "",
    userData["희망 직무 2순위 "] || "",
    userData["희망 직무 3순위 "] || "",
  ];
  targetJobs = targetJobs.map(job => job.trim()).filter(job => job);
  const targetEmploymentTypes = _parseEmploymentTypes(
    userData["희망 고용 형태 (복수선택)"] || ""
  );

  console.log(`사용자 희망 직무: ${targetJobs}`);
  console.log(`사용자 희망 회사: ${targetCompanies}`);
  console.log(`사용자 희망 고용형태: ${targetEmploymentTypes}`);

  // 단계별 필터링
  const step1Jobs = applyBasicFilters(userData, jobData);
  console.log(`1단계(경력) 후: ${step1Jobs.length}개 공고`);

  const step2Jobs = filterByEmploymentType(userData, step1Jobs);
  console.log(`2단계(고용형태) 후: ${step2Jobs.length}개 공고`);

  const step3Jobs = filterByJobRole(userData, step2Jobs);
  console.log(`3단계(직무) 후: ${step3Jobs.length}개 공고`);

  const finalJobs = filterByEducation(userData, step3Jobs);
  console.log(`4단계(학력) 후: ${finalJobs.length}개 공고`);

  if (finalJobs.length === 0) {
    console.log("필터링 후 추천할 공고가 없습니다");
    return [];
  }

  // 희망기업 분리
  const preferredJobs = [];
  const otherJobs = [];

  for (const job of finalJobs) {
    const companyName = job.company_name || job.company_name_from_file || "";
    const isPreferred = isPreferredCompany(targetCompanies, companyName);

    if (isPreferred) {
      preferredJobs.push(job);
    } else {
      otherJobs.push(job);
    }
  }

  console.log(`희망기업 공고: ${preferredJobs.length}개, 기타 공고: ${otherJobs.length}개`);

  // 정렬용 키 함수
  const userEducation = userData["찾고 계신 공고의 학력 조건을 선택해주세요. (졸업예정자도 선택 가능, 복수선택)"] || "";
  const userEduList = userEducation.split(",").map(edu => edu.trim()).filter(edu => edu);

  function sortKey(job) {
    return [
      countNulls(job),
      getJobRolePriority(targetJobs, job),
      getPriority(userEduList, job.min_education_level || ""),
      getPriority(targetEmploymentTypes, job.employment_type || ""),
      job.company_name || ""
    ];
  }

  // 튜플 비교 정렬 함수
  function compareSortKeys(a, b) {
    const keyA = sortKey(a);
    const keyB = sortKey(b);
    for (let i = 0; i < keyA.length; i++) {
      if (keyA[i] < keyB[i]) return -1;
      if (keyA[i] > keyB[i]) return 1;
    }
    return 0;
  }

  preferredJobs.sort(compareSortKeys);
  otherJobs.sort(compareSortKeys);
  const topJobs = [...preferredJobs, ...otherJobs].slice(0, topN);

  console.log(`추천 완료: ${topJobs.length}개 공고 선정`);

  return topJobs.map(job => ({
    job: job,
    is_preferred_company: isPreferredCompany(
      targetCompanies,
      job.company_name || job.company_name_from_file || ""
    ),
    score: 100
  }));
}

