  const userEmail = userData["이메일 주소"] || "";

  const matchedJobs = matchJobsForUser(userData, jobData);

  results.push({
    json: {
      user_name: userName,
      user_email: userEmail,
      matched_jobs: matchedJobs,
      matched_count: matchedJobs.length,
      preferred_count: matchedJobs.filter(j => j.is_preferred_company).length,
      top_5_jobs: matchedJobs.slice(0, 5).map(m => ({
        company: m.job.company_name || m.job.company_name_from_file || "",
        position: m.job.position_name || "",
        url: m.job.apply_url || "",
        is_preferred: m.is_preferred_company ? "⭐" : ""
      }))
    }
  });
}

return results;

